const Autumn = require('autumn-js');

const autumn = new Autumn({
  apiKey: process.env.AUTUMN_SECRET_KEY,
});

const checkApiQuota = async (req, res, next) => {
  const customerId = req.headers['x-customer-id'];

  if (!customerId) {
    return res.status(400).json({ error: "Missing customer ID" });
  }

  try {
    const checkResult = await autumn.customers.check({
      customerId: customerId,
      featureId: 'api-requests',
    });

    if (!checkResult.allowed) {
      return res.status(429).json({ error: "API quota exceeded", allowed: false });
    }

    await autumn.customers.track({
      customerId: customerId,
      featureId: 'api-requests',
      value: 1,
    });

    next();
  } catch (error) {
    console.error("Autumn API Error:", error);
    return res.status(500).json({ error: "Internal Server Error" });
  }
};

module.exports = { checkApiQuota };

